### Reschedule a Team Event with Booker Embed

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/atoms/booker-embed.mdx

Facilitate the rescheduling of a team event by providing the `rescheduleUid`, `isTeamEvent`, and `teamId` props to the `BookerEmbed` component. The `teamId` is the identifier for the specific team event. The `onCreateBookingSuccess` function executes after a successful reschedule.

```javascript
import { BookerEmbed } from "@calcom/atoms";

export default function BookerEmbed( props : BookerEmbedProps ) {
  return (
    <>
      <BookerEmbed
        eventSlug={props.eventTypeSlug}
        // rescheduleUid is the booking uid you get when you create a booking
        // it is only required when rescheduling a booking
        rescheduleUid={props.rescheduleUid}
        isTeamEvent={true}
        teamId={props.teamId}
        onCreateBookingSuccess={() => {
          console.log("Booking rescheduled successfully!");
         }}
      />
    </>
  )
}
```

